from flask import Flask, render_template, request, jsonify
import json
import sqlite3
from pathlib import Path

app = Flask(__name__)
DB = Path(__file__).parent / "data.db"


def db():
    conn = sqlite3.connect(DB)
    conn.row_factory = sqlite3.Row
    return conn


@app.route("/")
def home():
    return render_template("index.html")


